      { icone: "🍫", titre: "Crème pâtissière chocolat", detail: "Porter le lait avec gousse de vanille fendue. Pendant ce temps : fouetter jaunes d'œufs avec sucre jusqu'à blanchir + maïzena. Verser lait chaud, remettre sur feu, épaissir 2 min en fouettant. Hors du feu, ajouter chocolat noir 70%. Filmer au contact, refroidir.", badge: "⏱ 15 min" },
      { icone: "🥣", titre: "Pâte à choux", detail: "Eau + lait + beurre + sucre + sel dans casserole. Faire bouillir. Hors du feu : verser farine d'un coup, mélanger énergiquement. Remettre 2 min sur feu doux pour dessécher (la pâte se détache des bords).", badge: "⏱ 8 min" },
      { icone: "🥚", titre: "Incorporer œufs", detail: "Hors du feu, ajouter les œufs UN PAR UN, en mélangeant fortement entre chaque. La pâte doit former un V quand on lève la spatule (pas trop ferme, pas trop liquide).", badge: "⏱ 5 min" },
      { icone: "🎯", titre: "Pocher 2 tailles", detail: "Sur plaque avec papier sulfurisé, pocher des GROS choux (5 cm Ø) ET des PETITS choux (3 cm Ø). ASTUCE CHEF : il faut autant de petits que de gros. Dorer au pinceau (1 jaune + 1 cs lait).", badge: "⏱ 10 min" },
      { icone: "🔥", titre: "Cuire", detail: "Enfourner à 180°C chaleur tournante. CUISSON LONGUE : 25 min gros, 20 min petits. NE PAS OUVRIR LA PORTE pendant les 20 premières min. Sinon ils retombent !", badge: "⏱ 25 min" },
      { icone: "💦", titre: "Sécher", detail: "À la sortie, fendre légèrement chaque chou à la base avec couteau pointu pour libérer la vapeur. Refroidir COMPLÈTEMENT sur grille.", badge: "⏱ 1h" },
      { icone: "💉", titre: "Garnir", detail: "Avec une douille fine, percer chaque chou à la base. Garnir GÉNÉREUSEMENT de crème pâtissière chocolat (poche à douille avec embout pointu).", badge: "⏱ 15 min" },
      { icone: "✨", titre: "Glacer", detail: "Réchauffer le fondant à 35°C max (pas plus !). Ajouter cacao. Tremper le dessus de chaque chou. Égoutter rapidement avec le doigt.", badge: "⏱ 10 min" },
      { icone: "🏛️", titre: "Monter les religieuses", detail: "Poser un PETIT chou sur chaque GROS. ASTUCE CHEF : un peu de fondant entre les deux pour coller. Tradition : décorer la jointure avec crème au beurre en collerette (douille étoile). Servir frais.", badge: null }
